// // This module is designed to decrement a 4-bit binary counter on each rising edge of the clock signal. It resets to zero upon receiving a reset signal and sets the underflow flag when the count reaches its minimum value of 0.
module top_module(
    input clk,
    input reset,
    output reg [3:0] count,
    output reg overflow
);always @(posedge clk) begin
        if (reset) begin
            count <= 4'b0000;
            overflow <= 1'b0;
        end
        else begin
            if (count == 4'b1111) begin
                count <= 4'b0000;
                overflow <= 1'b1;
            end
            else begin
                count <= count + 1;
                overflow <= 1'b0;
            end
        end
    end

endmodule
